buildCommand:
mkdir -p src/environments && printf 'export const environment = {
  production: true,
  tmdbApiUrl: "https://api.themoviedb.org/3",
  tmdbImageBaseUrl: "https://image.tmdb.org/t/p",
  tmdbBearerToken: "%s",
};
' "$TMDB_BEARER_TOKEN" > src/environments/environment.prod.ts && printf 'export const environment = {
  production: false,
  tmdbApiUrl: "https://api.themoviedb.org/3",
  tmdbImageBaseUrl: "https://image.tmdb.org/t/p",
  tmdbBearerToken: "",
};
' > src/environments/environment.ts && npm run build
